    {"offset": {"line": 678, "column": 0}, "map": {"version":3,"sources":["file:///Users/angela/Desktop/portfolio-site-2026/portfolio-site/node_modules/next/src/lib/require-instrumentation-client.ts"],"sourcesContent":["/**\n * This module imports the client instrumentation hook from the project root.\n *\n * The `private-next-instrumentation-client` module is automatically aliased to\n * the `instrumentation-client.ts` file in the project root by webpack or turbopack.\n */\nif (process.env.NODE_ENV === 'development') {\n  const measureName = 'Client Instrumentation Hook'\n  const startTime = performance.now()\n  // eslint-disable-next-line @next/internal/typechecked-require -- Not a module.\n  module.exports = require('private-next-instrumentation-client')\n  const endTime = performance.now()\n  const duration = endTime - startTime\n\n  // Using 16ms threshold as it represents one frame (1000ms/60fps)\n  // This helps identify if the instrumentation hook initialization\n  // could potentially cause frame drops during development.\n  const THRESHOLD = 16\n  if (duration > THRESHOLD) {\n    console.log(\n      `[${measureName}] Slow execution detected: ${duration.toFixed(0)}ms (Note: Code download overhead is not included in this measurement)`\n    )\n  }\n} else {\n  // eslint-disable-next-line @next/internal/typechecked-require -- Not a module.\n  module.exports = require('private-next-instrumentation-client')\n}\n"],"names":["process","env","NODE_ENV","measureName","startTime","performance","now","module","exports","require","endTime","duration","THRESHOLD","console","log","toFixed"],"mappings":"AAMIA,QAAQC,GAAG,CAACC,QAAQ,KAAK;AAN7B;;;;;CAKC,GAAA;AACD,wCAA4C;IAC1C,MAAMC,cAAc;IACpB,MAAMC,YAAYC,YAAYC,GAAG;IACjC,+EAA+E;IAC/EC,OAAOC,OAAO,GAAGC,QAAQ;IACzB,MAAMC,UAAUL,YAAYC,GAAG;IAC/B,MAAMK,WAAWD,UAAUN;IAE3B,iEAAiE;IACjE,iEAAiE;IACjE,0DAA0D;IAC1D,MAAMQ,YAAY;IAClB,IAAID,WAAWC,WAAW;QACxBC,QAAQC,GAAG,CACT,CAAC,CAAC,EAAEX,YAAY,2BAA2B,EAAEQ,SAASI,OAAO,CAAC,GAAG,qEAAqE,CAAC;